dashboard.definition:
{
	"title": "Cluster Overview",
	"description": "Kubernetes cluster overview dashboard showing health, resource utilization, and top consumers",
	"inputs": {
		"input_cluster_selector": {
			"dataSources": {
				"primary": "ds_cluster_list"
			},
			"options": {
				"defaultValue": "*",
				"token": "cluster_token"
			},
			"title": "Select Cluster",
			"type": "input.dropdown"
		},
		"input_global_trp": {
			"options": {
				"defaultValue": "-60m@m,now",
				"token": "global_time"
			},
			"title": "Global Time Range",
			"type": "input.timerange"
		},
		"input_index_selector": {
			"options": {
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "index_token",
				"selectFirstSearchResult": true
			},
			"title": "Metric Index",
			"type": "input.dropdown",
			"dataSources": {
				"primary": "ds_5JYU0U1m"
			},
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [],
				"label": ">primary | seriesByName(\"metrics_index_key\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"metrics_index_value\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			}
		},
		"input_v9NpW6uC": {
			"options": {
				"items": ">frame(label, value) | prepend(formattedStatics) | objects()",
				"token": "logs_index",
				"selectFirstSearchResult": true
			},
			"title": "Logs Index",
			"type": "input.dropdown",
			"dataSources": {
				"primary": "ds_kglosEZr"
			},
			"context": {
				"formattedConfig": {
					"number": {
						"prefix": ""
					}
				},
				"formattedStatics": ">statics | formatByType(formattedConfig)",
				"statics": [],
				"label": ">primary | seriesByName(\"logs_index_key\") | renameSeries(\"label\") | formatByType(formattedConfig)",
				"value": ">primary | seriesByName(\"logs_index_value\") | renameSeries(\"value\") | formatByType(formattedConfig)"
			}
		}
	},
	"defaults": {
		"dataSources": {
			"ds.search": {
				"options": {
					"queryParameters": {
						"earliest": "$global_time.earliest$",
						"latest": "$global_time.latest$"
					},
					"refresh": "61s"
				}
			}
		}
	},
	"visualizations": {
		"viz_cluster_cpu": {
			"dataSources": {
				"primary": "ds_cluster_cpu"
			},
			"options": {
				"majorColor": "> majorValue | rangeValue(majorColorEditorConfig)",
				"majorColorEditorConfig": [
					{
						"color": "#118832",
						"to": 70,
						"value": 0
					},
					{
						"color": "#F5A800",
						"to": 85,
						"value": 70
					},
					{
						"color": "#D41F1F",
						"value": 85
					}
				],
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 4,
				"sparklineValues": "> primary | seriesByName('avg_cpu')",
				"unit": "cpu"
			},
			"title": "Cluster CPU Utilization",
			"type": "splunk.singlevalue"
		},
		"viz_cluster_memory": {
			"dataSources": {
				"primary": "ds_cluster_memory"
			},
			"options": {
				"majorColor": "> majorValue | rangeValue(majorColorEditorConfig)",
				"majorColorEditorConfig": [
					{
						"color": "#118832",
						"to": 70,
						"value": 0
					},
					{
						"color": "#F5A800",
						"to": 85,
						"value": 70
					},
					{
						"color": "#D41F1F",
						"value": 85
					}
				],
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 2,
				"sparklineValues": "> primary | seriesByName('avg_memory')",
				"unit": "%"
			},
			"title": "Cluster Memory Utilization",
			"type": "splunk.singlevalue"
		},
		"viz_healthy_nodes": {
			"dataSources": {
				"primary": "ds_healthy_nodes"
			},
			"options": {
				"majorColor": "> majorValue | rangeValue(majorColorEditorConfig)",
				"majorColorEditorConfig": [
					{
						"color": "#D41F1F",
						"to": 80,
						"value": 0
					},
					{
						"color": "#F5A800",
						"to": 95,
						"value": 80
					},
					{
						"color": "#118832",
						"value": 95
					}
				],
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 0,
				"sparklineValues": "> primary | seriesByName('healthy_nodes')",
				"unit": "% Ready"
			},
			"title": "Node Health",
			"type": "splunk.singlevalue"
		},
		"viz_namespace_memory": {
			"dataSources": {
				"primary": "ds_namespace_memory"
			},
			"description": "Memory (GB) consumed per namespace",
			"options": {
				"legendDisplay": "off",
				"seriesColors": [
					"#F5A800"
				],
				"xField": "total_memory_gb",
				"yField": "namespace"
			},
			"title": "Top Namespaces by Memory Usage",
			"type": "splunk.bar"
		},
		"viz_namespace_resources": {
			"dataSources": {
				"primary": "ds_namespace_resources"
			},
			"description": "CPU cores consumed per namespace",
			"options": {
				"legendDisplay": "off",
				"seriesColors": [
					"#1E93C6"
				],
				"xField": "total_cpu_cores",
				"yField": "namespace"
			},
			"title": "Top Namespaces by CPU Usage",
			"type": "splunk.bar"
		},
		"viz_node_status": {
			"context": {
				"drilldown": "node_detail"
			},
			"dataSources": {
				"primary": "ds_node_status"
			},
			"options": {
				"backgroundColor": "> table | seriesByName('status') | matchValue(statusMap)",
				"statusMap": {
					"NotReady": "#D41F1F",
					"Ready": "#118832",
					"Unknown": "#999999"
				},
				"tableFormat": {
					"align": "left"
				}
			},
			"title": "Node Status Overview",
			"type": "splunk.table"
		},
		"viz_recent_events": {
			"dataSources": {
				"primary": "ds_recent_events"
			},
			"description": "Cluster events",
			"options": {
				"backgroundColor": "> table | seriesByName('type') | matchValue(typeColorMap)",
				"typeColorMap": {
					"Error": "#D41F1F",
					"Normal": "#FFFFFF",
					"Warning": "#F5A800"
				}
			},
			"title": "Recent Kubernetes Events (Last 15)",
			"type": "splunk.table"
		},
		"viz_resource_timeline": {
			"dataSources": {
				"primary": "ds_resource_timeline"
			},
			"description": "CPU and Memory utilization over time",
			"options": {
				"legendDisplay": "bottom",
				"seriesColorsByField": {
					"cpu_percent": "#006D9C",
					"memory_percent": "#DD9900"
				},
				"xField": "_time",
				"y2": "> primary | frameBySeriesNames('memory_percent')"
			},
			"title": "Cluster Resource Usage",
			"type": "splunk.line"
		},
		"viz_running_pods": {
			"dataSources": {
				"primary": "ds_running_pods"
			},
			"options": {
				"majorColor": "> majorValue | rangeValue(majorColorEditorConfig)",
				"majorColorEditorConfig": [
					{
						"color": "#D41F1F",
						"to": 90,
						"value": 0
					},
					{
						"color": "#F5A800",
						"to": 98,
						"value": 90
					},
					{
						"color": "#118832",
						"value": 98
					}
				],
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 1,
				"sparklineValues": "> primary | seriesByName('running_percentage')",
				"unit": "%"
			},
			"title": "Running Pods",
			"type": "splunk.singlevalue"
		},
		"viz_top_cpu_pods": {
			"context": {
				"drilldown": "pod_detail"
			},
			"dataSources": {
				"primary": "ds_top_cpu_pods"
			},
			"title": "Top 10 Pods by CPU Usage",
			"type": "splunk.table"
		},
		"viz_top_memory_pods": {
			"context": {
				"drilldown": "pod_detail"
			},
			"dataSources": {
				"primary": "ds_top_memory_pods"
			},
			"title": "Top 10 Pods by Memory Usage",
			"type": "splunk.table"
		},
		"viz_total_nodes": {
			"dataSources": {
				"primary": "ds_total_nodes"
			},
			"description": "Total number of nodes in the cluster",
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 0,
				"sparklineValues": "> primary | seriesByName('count')",
				"trendDisplay": "percent",
				"trendValue": "> sparklineValues | delta(-2)",
				"unit": "Nodes"
			},
			"title": "Total Nodes",
			"type": "splunk.singlevalue"
		},
		"viz_total_pods": {
			"dataSources": {
				"primary": "ds_total_pods"
			},
			"options": {
				"majorValue": "> sparklineValues | lastPoint()",
				"numberPrecision": 0,
				"sparklineValues": "> primary | seriesByName('count')",
				"trendDisplay": "percent",
				"trendValue": "> sparklineValues | delta(-2)",
				"unit": "Pods"
			},
			"title": "Total Pods",
			"type": "splunk.singlevalue"
		}
	},
	"dataSources": {
		"ds_cluster_cpu": {
			"name": "Cluster CPU Utilization",
			"options": {
				"query": "| mstats p90(_value) as avg_cpu WHERE index=$index_token$ (metric_name=container.cpu.usage OR metric_name=k8s.pod.cpu.usage) k8s.cluster.name=$cluster_token$ span=1m",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_cluster_list": {
			"name": "Cluster List",
			"options": {
				"query": "| mcatalog values(k8s.cluster.name) AS clusters WHERE index=k8s_metrics | mvexpand clusters | rename clusters as label | eval value=label",
				"queryParameters": {
					"earliest": "-24h",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_cluster_memory": {
			"name": "Cluster Memory Utilization",
			"options": {
				"query": "| mstats avg(_value) as value WHERE index=$index_token$ (metric_name=container.memory.usage OR metric_name=container.memory.available) k8s.cluster.name=$cluster_token$ span=5m by metric_name \n| eval usage_percent=if(metric_name==\"container.memory.usage\", value, null()), available=if(metric_name==\"container.memory.available\", value, null()) \n| stats avg(usage_percent) as used, avg(available) as avail by _time \n| eval avg_memory=round((used/(used+avail))*100, 2) \n| fields _time, avg_memory",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_healthy_nodes": {
			"name": "Healthy Nodes Percentage",
			"options": {
				"query": "| mstats latest(_value) as ready_status WHERE index=$index_token$ metric_name=k8s.node.condition_ready k8s.cluster.name=$cluster_token$ by k8s.node.name \n| stats count as total, sum(ready_status) as ready \n| eval healthy_nodes=round((ready/total)*100, 2) \n| fields healthy_nodes",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_namespace_memory": {
			"name": "Namespace Memory Resources",
			"options": {
				"query": "| mstats sum(_value) as total_memory_bytes WHERE index=$index_token$ metric_name=container.memory.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=* by k8s.namespace.name \n| eval total_memory_gb=round(total_memory_bytes/1073741824, 2) \n| sort 10 -total_memory_gb \n| rename k8s.namespace.name as namespace",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_namespace_resources": {
			"name": "Namespace CPU Resources",
			"options": {
				"query": "| mstats avg(_value) as avg_cpu_percent WHERE index=$index_token$ metric_name=container.cpu.usage k8s.cluster.name=$cluster_token$ k8s.namespace.name=* by k8s.namespace.name, k8s.pod.name \n| stats avg(avg_cpu_percent) as avg_cpu_percent, dc(k8s.pod.name) as pod_count by k8s.namespace.name \n| eval total_cpu_cores=(avg_cpu_percent * pod_count)/100 \n| sort 10 -total_cpu_cores \n| rename k8s.namespace.name as namespace",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_node_status": {
			"name": "Node Status",
			"options": {
				"query": "| mstats latest(_value) as ready_val WHERE index=$index_token$ metric_name=k8s.node.condition_ready k8s.cluster.name=$cluster_token$ k8s.node.name=* by k8s.node.name \n| eval Status=if(ready_val==1, \"Ready\", if(ready_val==0, \"NotReady\", \"Unknown\")) \n| join type=left k8s.node.name \n    [| mstats p90(_value) as cpu_usage WHERE index=$index_token$ metric_name=container.cpu.usage k8s.cluster.name=$cluster_token$ k8s.node.name=* by k8s.node.name] \n| join type=left k8s.node.name \n    [| mstats latest(_value) as phase WHERE index=$index_token$ metric_name=k8s.pod.phase k8s.cluster.name=$cluster_token$ by k8s.pod.name, k8s.node.name \n    | stats dc(k8s.pod.name) as pod_count by k8s.node.name] \n| fillnull value=0 cpu_percent, pod_count \n| eval \"Avg CPU usage cores\"=round(cpu_usage, 4), \"Pod Count\"=pod_count \n| rename k8s.node.name as \"Node Name\" \n| table \"Node Name\", Status, \"Avg CPU usage cores\", \"Pod Count\" \n| sort -\"Avg CPU usage cores\"",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_recent_events": {
			"name": "Recent Events",
			"options": {
				"query": "index=$logs_index$ k8s.cluster.name=$cluster_token$ (source=*kube-events* OR sourcetype=kube:events)| head 15 | table _time, \"otel.log.severity.text\", k8s.namespace.name, k8s.event.reason, _raw | rename _time as Time, \"otel.log.severity.text\" as Type, k8s.namespace.name as Namespace, k8s.event.reason as Reason, _raw as Message | sort -Time\n| eval Time = strftime(Time, \"%Y-%m-%d %H:%M:%S\")",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_resource_timeline": {
			"name": "Resource Timeline",
			"options": {
				"query": "| mstats avg(_value) as value WHERE index=$index_token$ (metric_name=container.cpu.usage OR metric_name=container.memory.usage OR metric_name=container.memory.available) k8s.cluster.name=$cluster_token$ span=1m by metric_name \n| eval cpu=if(metric_name==\"container.cpu.usage\", value, null()), mem_used=if(metric_name==\"container.memory.usage\", value, null()), mem_avail=if(metric_name==\"container.memory.available\", value, null()) \n| stats p90(cpu) as avg_cpu_cores, p90(mem_used) as mem_u, p90(mem_avail) as mem_a by _time \n| eval memory_percent=round((mem_u/(mem_u+mem_a))*100, 2) \n| fields _time, avg_cpu_cores, memory_percent",
				"queryParameters": {
					"earliest": "-24h",
					"latest": "now"
				}
			},
			"type": "ds.search"
		},
		"ds_running_pods": {
			"name": "Running Pods Percentage",
			"options": {
				"query": "| mstats latest(_value) as phase WHERE index=$index_token$ metric_name=k8s.pod.phase k8s.cluster.name=$cluster_token$ by k8s.pod.name \n| stats count as total, count(eval(phase==2 OR phase==\"Running\" OR phase==3)) as running \n| eval running_percentage=round((running/total)*100, 2) \n| fields running_percentage",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_top_cpu_pods": {
			"name": "Top CPU Pods",
			"options": {
				"query": "| mstats p90(_value) as avg_cpu WHERE index=$index_token$ metric_name=container.cpu.usage k8s.cluster.name=$cluster_token$ by k8s.pod.name, k8s.namespace.name \n| sort 10 -avg_cpu \n| eval avg_cpu=round(avg_cpu, 4) \n| rename k8s.pod.name as \"Pod Name\", k8s.namespace.name as Namespace, avg_cpu as \"CPU cores\"| table \"Pod Name\", Namespace, \"CPU cores\"",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_top_memory_pods": {
			"name": "Top Memory Pods",
			"options": {
				"query": "| mstats avg(_value) as avg_memory_bytes WHERE index=$index_token$ metric_name=container.memory.usage k8s.cluster.name=$cluster_token$ by k8s.pod.name, k8s.namespace.name \n| eval avg_memory_mb=round(avg_memory_bytes/1048576, 2) \n| sort 10 -avg_memory_mb \n| rename k8s.pod.name as \"Pod Name\", k8s.namespace.name as Namespace, avg_memory_mb as \"Memory (MB)\" \n| table \"Pod Name\", Namespace, \"Memory (MB)\"",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_total_nodes": {
			"name": "Total Nodes",
			"options": {
				"query": "| mstats latest(_value) as ready_val WHERE index=$index_token$ metric_name=k8s.node.condition_ready k8s.cluster.name=$cluster_token$ span=5m by k8s.node.name | timechart span=5m dc(k8s.node.name) as count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_total_pods": {
			"name": "Total Pods",
			"options": {
				"query": "| mstats latest(_value) as phase WHERE index=$index_token$ metric_name=k8s.pod.phase k8s.cluster.name=$cluster_token$ span=5m by k8s.pod.name | timechart span=5m dc(k8s.pod.name) as count",
				"queryParameters": {
					"earliest": "$global_time.earliest$",
					"latest": "$global_time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_5JYU0U1m": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup append=t k8s_metrics_indexes_dropdown_lookup.csv"
			},
			"name": "metrics_index_dropdown"
		},
		"ds_kglosEZr": {
			"type": "ds.search",
			"options": {
				"query": "| inputlookup append=t k8s_logs_events_indexes_dropdown_lookup.csv"
			},
			"name": "logs_index_dropdown"
		}
	},
	"layout": {
		"globalInputs": [
			"input_global_trp",
			"input_index_selector",
			"input_v9NpW6uC",
			"input_cluster_selector"
		],
		"layoutDefinitions": {
			"layout_1": {
				"structure": [
					{
						"item": "viz_total_nodes",
						"position": {
							"h": 150,
							"w": 200,
							"x": 0,
							"y": 0
						},
						"type": "block"
					},
					{
						"item": "viz_healthy_nodes",
						"position": {
							"h": 150,
							"w": 200,
							"x": 200,
							"y": 0
						},
						"type": "block"
					},
					{
						"item": "viz_total_pods",
						"position": {
							"h": 150,
							"w": 200,
							"x": 400,
							"y": 0
						},
						"type": "block"
					},
					{
						"item": "viz_running_pods",
						"position": {
							"h": 150,
							"w": 200,
							"x": 600,
							"y": 0
						},
						"type": "block"
					},
					{
						"item": "viz_cluster_cpu",
						"position": {
							"h": 150,
							"w": 200,
							"x": 800,
							"y": 0
						},
						"type": "block"
					},
					{
						"item": "viz_cluster_memory",
						"position": {
							"h": 150,
							"w": 200,
							"x": 1000,
							"y": 0
						},
						"type": "block"
					},
					{
						"item": "viz_resource_timeline",
						"position": {
							"h": 300,
							"w": 1200,
							"x": 0,
							"y": 150
						},
						"type": "block"
					},
					{
						"item": "viz_namespace_resources",
						"position": {
							"h": 300,
							"w": 600,
							"x": 0,
							"y": 450
						},
						"type": "block"
					},
					{
						"item": "viz_namespace_memory",
						"position": {
							"h": 300,
							"w": 600,
							"x": 600,
							"y": 450
						},
						"type": "block"
					},
					{
						"item": "viz_node_status",
						"position": {
							"h": 250,
							"w": 1200,
							"x": 0,
							"y": 750
						},
						"type": "block"
					},
					{
						"item": "viz_recent_events",
						"position": {
							"h": 300,
